SELECT id, borrow_record_id, user_id, device_id, overdue_hours, overdue_days, processing_status,
       processing_method, processing_remark, processor_id, processing_time, compensation_amount,
       notification_sent, created_at, updated_at
FROM overdue_record
WHERE 1 = 1

      AND processing_status = #{processingStatus}


      AND user_id = #{userId}

ORDER BY created_at DESC, overdue_hours DESC
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(1)
FROM overdue_record
WHERE 1 = 1

      AND processing_status = #{processingStatus}


      AND user_id = #{userId}

